def evaluate(expr: str) -> float:
    tokens = []
    i = 0
    while i < len(expr):
        if expr[i].isspace():
            i += 1
        elif expr[i:i+2] == '**':
            tokens.append('**')
            i += 2
        elif expr[i] in '+-*/()':
            tokens.append(expr[i])
            i += 1
        elif expr[i].isdigit() or expr[i] == '.':
            j = i
            has_digit = False
            dot_pos = -1

            while j < len(expr) and (expr[j].isdigit() or (expr[j] == '.' and dot_pos == -1)):
                if expr[j].isdigit():
                    has_digit = True
                else:
                    dot_pos = j
                j += 1

            if not has_digit:
                raise ValueError("Invalid number")

            tokens.append(float(expr[i:j]))
            i = j
        else:
            raise ValueError("Illegal character")

    if not tokens:
        raise ValueError("Empty expression")

    pos = 0

    def peek():
        return tokens[pos] if pos < len(tokens) else None

    def consume():
        nonlocal pos
        token = tokens[pos]
        pos += 1
        return token

    def expr_rule():
        left = term()
        while peek() in ('+', '-'):
            op = consume()
            right = term()
            if op == '+':
                left = left + right
            else:
                left = left - right
        return left

    def term():
        left = factor()
        while peek() in ('*', '/'):
            op = consume()
            right = factor()
            if op == '*':
                left = left * right
            else:
                if right == 0:
                    raise ZeroDivisionError()
                left = left / right
        return left

    def factor():
        return unary()

    def unary():
        if peek() == '-':
            consume()
            return -unary()
        else:
            return power()

    def power():
        base = atom()
        if peek() == '**':
            consume()
            exp = unary()
            return base ** exp
        return base

    def atom():
        token = peek()
        if token is None:
            raise ValueError("Unexpected end of expression")
        elif isinstance(token, (int, float)):
            consume()
            return float(token)
        elif token == '(':
            consume()
            result = expr_rule()
            if peek() != ')':
                raise ValueError("Unbalanced parentheses")
            consume()
            return result
        else:
            raise ValueError("Unexpected token")

    result = expr_rule()
    if pos < len(tokens):
        raise ValueError("Unexpected token")

    return result
